     1→// Phase 5: TypeChecker - 정적 타입 검증
     2→
     3→import { Expr, Stmt, Program, CapabilityAnnotation, Param } from "./ast"
     4→import {
     5→  Type,
     6→  PrimitiveType,
     7→  TypeCheckError,
     8→  TypeCheckResult,
     9→  typesCompatible,
    10→  typeToString,
    11→  getOperationResultType,
    12→  inferTypeFromValue,
    13→  BUILTIN_TYPES,
    14→  Capability,
    15→  CapabilityKind,
    16→  parseType,  // Phase 5.5.3: 어노테이션 문자열 → Type 변환
    17→} from "./type-system"
    18→
    19→/**
    20→ * TypeChecker: AST 기반 정적 타입 검증
    21→ */
    22→export class TypeChecker {
    23→  private env: Map<string, Type> = new Map()
    24→  private functionTypes: Map<string, Type> = new Map()
    25→  private errors: TypeCheckError[] = []
    26→  private currentFunctionReturnTypes: Type[] = []
    27→  private currentCapabilities: Capability[] = []
    28→
    29→  // Phase 6: Built-in 함수 required capability
    30→  private readonly BUILTIN_REQUIRED_CAPABILITIES: Map<string, CapabilityKind> = new Map([
    31→    ["file_read", "read_file"],
    32→    ["file_write", "write_file"],
    33→    ["http_request", "network"],
    34→    ["http_get", "network"],
    35→    ["process_spawn", "spawn_process"],
    36→    ["eval", "execute_code"],
    37→  ])
    38→
    39→  /**
    40→   * 전체 프로그램 타입 검사
    41→   */
    42→  public check(program: Program): TypeCheckResult {
    43→    this.errors = []
    44→    this.env.clear()
    45→    this.functionTypes.clear()
    46→
    47→    // First pass: 함수 정의 수집
    48→    for (const stmt of program.stmts) {
    49→      if (stmt.kind === "fn") {
    50→        this.registerFunctionType(stmt)
    51→      }
    52→    }
    53→
    54→    // Second pass: 함수 본문 및 다른 명령문 검사
    55→    for (const stmt of program.stmts) {
    56→      this.checkStmt(stmt)
    57→    }
    58→
    59→    return {
    60→      success: this.errors.length === 0,
    61→      errors: this.errors,
    62→      types: new Map(this.env),
    63→    }
    64→  }
    65→
    66→  /**
    67→   * 수집된 return 타입들로부터 함수의 반환 타입 추론
    68→   */
    69→  private inferReturnType(types: Type[]): Type {
    70→    if (types.length === 0) return BUILTIN_TYPES.UNKNOWN
    71→    const first = types[0]
    72→    if (types.every(t => JSON.stringify(t) === JSON.stringify(first)))
    73→      return first
    74→    return BUILTIN_TYPES.UNKNOWN
    75→  }
    76→
    77→  /**
    78→   * 함수 타입 등록
    79→   */
    80→  private registerFunctionType(stmt: Stmt): void {
    81→    if (stmt.kind === "fn") {
    82→      const fnStmt = stmt as any
    83→      // Phase 5.5.3: 어노테이션이 있으면 해당 타입, 없으면 UNKNOWN
    84→      const paramTypes: Type[] = (fnStmt.params || []).map((p: any) =>
    85→        parseType(p.typeAnnotation ?? "unknown")
    86→      )
    87→
    88→      const returnType: Type = {
    89→        kind: "primitive",
    90→        type: PrimitiveType.UNKNOWN,
    91→      }
    92→
    93→      // Phase 6: annotations → capabilities 변환
    94→      const capabilities: Capability[] = (fnStmt.annotations || [])
    95→        .filter((a: any) => a.kind === "allow")
    96→        .map((a: any) => ({ cap: a.cap, arg: a.arg }))
    97→
    98→      const fnType: Type = {
    99→        kind: "fn",
   100→        paramTypes,
   101→        returnType,
   102→        capabilities,
   103→      }
   104→
   105→      this.functionTypes.set(fnStmt.name, fnType)
   106→    }
   107→  }
   108→
   109→  /**
   110→   * 명령문 타입 검사
   111→   */
   112→  private checkStmt(stmt: Stmt): void {
   113→    switch (stmt.kind) {
   114→      case "print": {
   115→        const printStmt = stmt as any
   116→        this.checkExpr(printStmt.expr)
   117→        break
   118→      }
   119→
   120→      case "expr": {
   121→        const exprStmt = stmt as any
   122→        this.checkExpr(exprStmt.expr)
   123→        break
   124→      }
   125→
   126→      case "let": {
   127→        const letStmt = stmt as any
   128→        if (letStmt.init) {
   129→          const valueType = this.checkExpr(letStmt.init)
   130→          this.env.set(letStmt.name, valueType)
   131→        } else {
   132→          this.env.set(letStmt.name, BUILTIN_TYPES.UNKNOWN)
   133→        }
   134→        break
   135→      }
   136→
   137→      case "fn": {
   138→        const fnStmt = stmt as any
   139→        const savedEnv = new Map(this.env)
   140→        const savedReturnTypes = this.currentFunctionReturnTypes
   141→        const savedCapabilities = this.currentCapabilities
   142→
   143→        // Phase 6: 현재 함수의 선언 capability로 컨텍스트 설정
   144→        const fnType = this.functionTypes.get(fnStmt.name)
   145→        this.currentCapabilities = fnType?.kind === "fn"
   146→          ? (fnType.capabilities ?? [])
   147→          : []
   148→
   149→        this.currentFunctionReturnTypes = []
   150→
   151→        // Phase 5.5.3: 파라미터 어노테이션 기반 타입 등록
   152→        for (const param of fnStmt.params || []) {
   153→          this.env.set(param.name, parseType(param.typeAnnotation ?? "unknown"))
   154→        }
   155→
   156→        // 함수 본문 검사
   157→        for (const s of fnStmt.body || []) {
   158→          this.checkStmt(s)
   159→        }
   160→
   161→        // return 타입 추론 후 functionTypes 갱신
   162→        const inferredReturn = this.inferReturnType(
   163→          this.currentFunctionReturnTypes
   164→        )
   165→        const existingFnType = this.functionTypes.get(fnStmt.name)
   166→        if (existingFnType && existingFnType.kind === "fn") {
   167→          this.functionTypes.set(fnStmt.name, {
   168→            kind: "fn",
   169→            paramTypes: existingFnType.paramTypes,
   170→            returnType: inferredReturn,
   171→            capabilities: existingFnType.capabilities, // Phase 6: 보존
   172→          })
   173→        }
   174→
   175→        this.currentCapabilities = savedCapabilities
   176→        this.currentFunctionReturnTypes = savedReturnTypes
   177→        this.env = savedEnv
   178→        break
   179→      }
   180→
   181→      case "if": {
   182→        const ifStmt = stmt as any
   183→        this.checkExpr(ifStmt.cond)
   184→        for (const s of ifStmt.then || []) {
   185→          this.checkStmt(s)
   186→        }
   187→        if (ifStmt.else) {
   188→          for (const s of ifStmt.else) {
   189→            this.checkStmt(s)
   190→          }
   191→        }
   192→        break
   193→      }
   194→
   195→      case "for": {
   196→        const forStmt = stmt as any
   197→        this.checkExpr(forStmt.iter)
   198→        // 루프 변수를 환경에 추가
   199→        this.env.set(forStmt.name, BUILTIN_TYPES.UNKNOWN)
   200→        for (const s of forStmt.body || []) {
   201→          this.checkStmt(s)
   202→        }
   203→        break
   204→      }
   205→
   206→      case "while": {
   207→        const whileStmt = stmt as any
   208→        this.checkExpr(whileStmt.cond)
   209→        for (const s of whileStmt.body || []) {
   210→          this.checkStmt(s)
   211→        }
   212→        break
   213→      }
   214→
   215→      case "return": {
   216→        const returnStmt = stmt as any
   217→        if (returnStmt.value) {
   218→          const retType = this.checkExpr(returnStmt.value)
   219→          this.currentFunctionReturnTypes.push(retType)
   220→        }
   221→        break
   222→      }
   223→
   224→      case "block": {
   225→        const blockStmt = stmt as any
   226→        for (const s of blockStmt.body || []) {
   227→          this.checkStmt(s)
   228→        }
   229→        break
   230→      }
   231→
   232→      case "try": {
   233→        const tryStmt = stmt as any
   234→        for (const s of tryStmt.body || []) {
   235→          this.checkStmt(s)
   236→        }
   237→        if (tryStmt.catchVar) {
   238→          this.env.set(tryStmt.catchVar, BUILTIN_TYPES.UNKNOWN)
   239→        }
   240→        for (const s of tryStmt.catchBody || []) {
   241→          this.checkStmt(s)
   242→        }
   243→        for (const s of tryStmt.finallyBody || []) {
   244→          this.checkStmt(s)
   245→        }
   246→        break
   247→      }
   248→
   249→      case "throw": {
   250→        const throwStmt = stmt as any
   251→        this.checkExpr(throwStmt.expr)
   252→        break
   253→      }
   254→
   255→      case "if-let": {
   256→        const ifLetStmt = stmt as any
   257→        this.checkExpr(ifLetStmt.value)
   258→        // 패턴 바인딩
   259→        if (ifLetStmt.pattern.kind === "ident") {
   260→          this.env.set(ifLetStmt.pattern.name, BUILTIN_TYPES.UNKNOWN)
   261→        }
   262→        for (const s of ifLetStmt.body || []) {
   263→          this.checkStmt(s)
   264→        }
   265→        if (ifLetStmt.else) {
   266→          for (const s of ifLetStmt.else) {
   267→            this.checkStmt(s)
   268→          }
   269→        }
   270→        break
   271→      }
   272→
   273→      case "while-let": {
   274→        const whileLetStmt = stmt as any
   275→        this.checkExpr(whileLetStmt.value)
   276→        if (whileLetStmt.pattern.kind === "ident") {
   277→          this.env.set(whileLetStmt.pattern.name, BUILTIN_TYPES.UNKNOWN)
   278→        }
   279→        for (const s of whileLetStmt.body || []) {
   280→          this.checkStmt(s)
   281→        }
   282→        break
   283→      }
   284→
   285→      case "match": {
   286→        const matchStmt = stmt as any
   287→        this.checkExpr(matchStmt.subject)
   288→        for (const arm of matchStmt.arms || []) {
   289→          if (arm.pattern) {
   290→            this.checkExpr(arm.pattern)
   291→          }
   292→          if (arm.guard) {
   293→            this.checkExpr(arm.guard)
   294→          }
   295→          for (const s of arm.body || []) {
   296→            this.checkStmt(s)
   297→          }
   298→        }
   299→        break
   300→      }
   301→    }
   302→  }
   303→
   304→  /**
   305→   * 표현식 타입 검사
   306→   */
   307→  public checkExpr(expr: Expr): Type {
   308→    switch (expr.kind) {
   309→      case "number":
   310→        return { kind: "primitive", type: PrimitiveType.NUM }
   311→
   312→      case "string":
   313→        return { kind: "primitive", type: PrimitiveType.STR }
   314→
   315→      case "bool":
   316→        return { kind: "primitive", type: PrimitiveType.BOOL }
   317→
   318→      case "null":
   319→        return { kind: "primitive", type: PrimitiveType.NULL }
   320→
   321→      case "ident": {
   322→        const identExpr = expr as any
   323→        const type = this.env.get(identExpr.name)
   324→        if (!type) {
   325→          this.addError(
   326→            `Undefined variable '${identExpr.name}'`,
   327→            undefined,
   328→            undefined
   329→          )
   330→          return BUILTIN_TYPES.UNKNOWN
   331→        }
   332→        return type
   333→      }
   334→
   335→      case "assign": {
   336→        const assignExpr = expr as any
   337→        const valueType = this.checkExpr(assignExpr.value)
   338→
   339→        // target이 ident인 경우 할당
   340→        if (assignExpr.target.kind === "ident") {
   341→          this.env.set(assignExpr.target.name, valueType)
   342→        }
   343→        return valueType
   344→      }
   345→
   346→      case "binary": {
   347→        const binExpr = expr as any
   348→        const leftType = this.checkExpr(binExpr.left)
   349→        const rightType = this.checkExpr(binExpr.right)
   350→
   351→        // 타입 호환성 검사
   352→        const resultType = getOperationResultType(
   353→          binExpr.op,
   354→          leftType,
   355→          rightType
   356→        )
   357→
   358→        // Add 연산 검증
   359→        if (binExpr.op === "+" || binExpr.op === "Add") {
   360→          if (leftType.kind === "primitive" && rightType.kind === "primitive") {
   361→            const left = leftType.type
   362→            const right = rightType.type
   363→
   364→            if (
   365→              !(
   366→                (left === PrimitiveType.NUM && right === PrimitiveType.NUM) ||
   367→                (left === PrimitiveType.STR || right === PrimitiveType.STR) ||
   368→                (left === PrimitiveType.UNKNOWN ||
   369→                  right === PrimitiveType.UNKNOWN)
   370→              )
   371→            ) {
   372→              this.addError(
   373→                `Cannot add ${typeToString(leftType)} and ${typeToString(rightType)}`,
   374→                undefined,
   375→                undefined,
   376→                undefined,
   377→                leftType,
   378→                rightType
   379→              )
   380→            }
   381→          }
   382→        }
   383→
   384→        return resultType
   385→      }
   386→
   387→      case "unary": {
   388→        const unaryExpr = expr as any
   389→        const operandType = this.checkExpr(unaryExpr.expr)
   390→
   391→        if (unaryExpr.op === "!") {
   392→          if (
   393→            operandType.kind !== "primitive" ||
   394→            operandType.type !== PrimitiveType.BOOL
   395→          ) {
   396→            this.addError(
   397→              `Cannot apply ! to ${typeToString(operandType)}`,
   398→              undefined,
   399→              undefined
   400→            )
   401→          }
   402→          return BUILTIN_TYPES.BOOL
   403→        }
   404→
   405→        if (unaryExpr.op === "-") {
   406→          if (
   407→            operandType.kind !== "primitive" ||
   408→            operandType.type !== PrimitiveType.NUM
   409→          ) {
   410→            this.addError(
   411→              `Cannot negate ${typeToString(operandType)}`,
   412→              undefined,
   413→              undefined
   414→            )
   415→          }
   416→          return BUILTIN_TYPES.NUM
   417→        }
   418→
   419→        return operandType
   420→      }
   421→
   422→      case "call": {
   423→        const callExpr = expr as any
   424→
   425→        // callee에서 함수 이름 추출
   426→        let fnName = ""
   427→        if (callExpr.callee.kind === "ident") {
   428→          fnName = callExpr.callee.name
   429→        }
   430→
   431→        // Phase 6: Built-in 함수 required capability 검사
   432→        const builtinRequired = this.BUILTIN_REQUIRED_CAPABILITIES.get(fnName)
   433→        if (builtinRequired) {
   434→          const callerHas = this.currentCapabilities.some(c => c.cap === builtinRequired)
   435→          if (!callerHas) {
   436→            this.addError(
   437→              `'${fnName}' requires capability '${builtinRequired}', not declared`,
   438→              undefined,
   439→              undefined
   440→            )
   441→          }
   442→        }
   443→
   444→        const fnType = this.functionTypes.get(fnName)
   445→
   446→        if (!fnType) {
   447→          this.addError(
   448→            `Undefined function '${fnName}'`,
   449→            undefined,
   450→            undefined
   451→          )
   452→          return BUILTIN_TYPES.UNKNOWN
   453→        }
   454→
   455→        if (fnType.kind === "fn") {
   456→          // 인자 개수 확인
   457→          if ((callExpr.args || []).length !== fnType.paramTypes.length) {
   458→            this.addError(
   459→              `Function '${fnName}' expects ${fnType.paramTypes.length} arguments, got ${(callExpr.args || []).length}`,
   460→              undefined,
   461→              undefined
   462→            )
   463→          }
   464→
   465→          // 인자 타입 검사
   466→          for (let i = 0; i < (callExpr.args || []).length; i++) {
   467→            const argType = this.checkExpr(callExpr.args[i])
   468→            const paramType = fnType.paramTypes[i] || BUILTIN_TYPES.UNKNOWN
   469→
   470→            if (!typesCompatible(argType, paramType)) {
   471→              this.addError(
   472→                `Argument ${i} of '${fnName}': expected ${typeToString(paramType)}, got ${typeToString(argType)}`,
   473→                undefined,
   474→                undefined,
   475→                undefined,
   476→                paramType,
   477→                argType
   478→              )
   479→            }
   480→          }
   481→
   482→          // Phase 6: Capability Propagation 검증
   483→          // Strict: callee.capabilities ⊆ caller.capabilities
   484→          if (fnType.capabilities && fnType.capabilities.length > 0) {
   485→            for (const required of fnType.capabilities) {
   486→              const callerHas = this.currentCapabilities.some(
   487→                c => c.cap === required.cap && this.capabilityCovers(c, required)
   488→              )
   489→              if (!callerHas) {
   490→                this.addError(
   491→                  `Call to '${fnName}' requires capability '${required.cap}' ` +
   492→                  `${required.arg ? `(${required.arg})` : ""}, ` +
   493→                  `but caller does not declare it`,
   494→                  undefined,
   495→                  undefined
   496→                )
   497→              }
   498→            }
   499→          }
   500→
   501→          return fnType.returnType
   502→        }
   503→
   504→        return BUILTIN_TYPES.UNKNOWN
   505→      }
   506→
   507→      case "array": {
   508→        const arrayExpr = expr as any
   509→        if ((arrayExpr.elements || []).length === 0) {
   510→          return {
   511→            kind: "array",
   512→            elementType: BUILTIN_TYPES.UNKNOWN,
   513→          }
   514→        }
   515→
   516→        const elementTypes = (arrayExpr.elements || []).map((e: any) =>
   517→          this.checkExpr(e)
   518→        )
   519→
   520→        // 모든 요소 타입이 같은지 확인
   521→        const firstType = elementTypes[0]
   522→        for (let i = 1; i < elementTypes.length; i++) {
   523→          if (!typesCompatible(elementTypes[i], firstType)) {
   524→            this.addError(
   525→              `Array elements have inconsistent types: ${typeToString(firstType)} and ${typeToString(elementTypes[i])}`,
   526→              undefined,
   527→              undefined
   528→            )
   529→          }
   530→        }
   531→
   532→        return {
   533→          kind: "array",
   534→          elementType: firstType,
   535→        }
   536→      }
   537→
   538→      case "index": {
   539→        const indexExpr = expr as any
   540→        const objectType = this.checkExpr(indexExpr.object)
   541→        this.checkExpr(indexExpr.index)
   542→
   543→        if (objectType.kind === "array") {
   544→          return objectType.elementType
   545→        }
   546→        return BUILTIN_TYPES.UNKNOWN
   547→      }
   548→
   549→      case "member": {
   550→        const memberExpr = expr as any
   551→        const objectType = this.checkExpr(memberExpr.object)
   552→
   553→        if (objectType.kind === "object") {
   554→          const propType = objectType.properties.get(memberExpr.property)
   555→          return propType || BUILTIN_TYPES.UNKNOWN
   556→        }
   557→        return BUILTIN_TYPES.UNKNOWN
   558→      }
   559→
   560→      case "object": {
   561→        const objExpr = expr as any
   562→        const properties = new Map<string, Type>()
   563→
   564→        for (const entry of objExpr.entries || []) {
   565→          properties.set(entry.key, this.checkExpr(entry.value))
   566→        }
   567→
   568→        return {
   569→          kind: "object",
   570→          properties,
   571→        }
   572→      }
   573→
   574→      case "fn": {
   575→        const fnExpr = expr as any
   576→        const savedEnv = new Map(this.env)
   577→        const savedReturnTypes = this.currentFunctionReturnTypes
   578→
   579→        this.currentFunctionReturnTypes = []
   580→
   581→        // Phase 5.5.3: fn 표현식 파라미터도 어노테이션 적용
   582→        for (const param of fnExpr.params || []) {
   583→          this.env.set(param.name, parseType(param.typeAnnotation ?? "unknown"))
   584→        }
   585→
   586→        // 함수 본문 검사
   587→        for (const stmt of fnExpr.body || []) {
   588→          this.checkStmt(stmt)
   589→        }
   590→
   591→        const inferredReturn = this.inferReturnType(
   592→          this.currentFunctionReturnTypes
   593→        )
   594→        // Phase 5.5.3: fn 표현식도 어노테이션 기반 paramTypes
   595→        const paramTypes: Type[] = (fnExpr.params || []).map((p: any) =>
   596→          parseType(p.typeAnnotation ?? "unknown")
   597→        )
   598→
   599→        this.currentFunctionReturnTypes = savedReturnTypes
   600→        this.env = savedEnv
   601→
   602→        return {
   603→          kind: "fn",
   604→          paramTypes,
   605→          returnType: inferredReturn,
   606→        }
   607→      }
   608→
   609→      case "ternary": {
   610→        const ternaryExpr = expr as any
   611→        this.checkExpr(ternaryExpr.cond)
   612→        const thenType = this.checkExpr(ternaryExpr.then)
   613→        const elseType = this.checkExpr(ternaryExpr.else)
   614→
   615→        // then과 else 타입이 호환 가능해야 함
   616→        if (!typesCompatible(thenType, elseType)) {
   617→          this.addError(
   618→            `Ternary branch types incompatible: ${typeToString(thenType)} vs ${typeToString(elseType)}`,
   619→            undefined,
   620→            undefined
   621→          )
   622→        }
   623→
   624→        return thenType
   625→      }
   626→
   627→      case "if": {
   628→        const ifExpr = expr as any
   629→        this.checkExpr(ifExpr.cond)
   630→        for (const s of ifExpr.then || []) {
   631→          this.checkStmt(s)
   632→        }
   633→        for (const s of ifExpr.else || []) {
   634→          this.checkStmt(s)
   635→        }
   636→        return BUILTIN_TYPES.UNKNOWN
   637→      }
   638→
   639→      case "match": {
   640→        const matchExpr = expr as any
   641→        this.checkExpr(matchExpr.subject)
   642→        for (const arm of matchExpr.arms || []) {
   643→          if (arm.pattern) {
   644→            this.checkExpr(arm.pattern)
   645→          }
   646→          if (arm.guard) {
   647→            this.checkExpr(arm.guard)
   648→          }
   649→          for (const s of arm.body || []) {
   650→            this.checkStmt(s)
   651→          }
   652→        }
   653→        return BUILTIN_TYPES.UNKNOWN
   654→      }
   655→
   656→      default:
   657→        return BUILTIN_TYPES.UNKNOWN
   658→    }
   659→  }
   660→
   661→  /**
   662→   * 오류 추가
   663→   */
   664→  private addError(
   665→    message: string,
   666→    line?: number,
   667→    column?: number,
   668→    variable?: string,
   669→    expected?: Type,
   670→    actual?: Type
   671→  ): void {
   672→    this.errors.push({
   673→      message,
   674→      line,
   675→      column,
   676→      variable,
   677→      expected,
   678→      actual,
   679→    })
   680→  }
   681→
   682→  /**
   683→   * 환경 조회
   684→   */
   685→  public getEnv(): Map<string, Type> {
   686→    return new Map(this.env)
   687→  }
   688→
   689→  /**
   690→   * 함수 타입 조회
   691→   */
   692→  public getFunctionType(name: string): Type | undefined {
   693→    return this.functionTypes.get(name)
   694→  }
   695→
   696→  /**
   697→   * 오류 개수
   698→   */
   699→  public getErrorCount(): number {
   700→    return this.errors.length
   701→  }
   702→
   703→  /**
   704→   * 오류 목록
   705→   */
   706→  public getErrors(): TypeCheckError[] {
   707→    return [...this.errors]
   708→  }
   709→
   710→  /**
   711→   * Phase 6: Capability 헬퍼 함수들
   712→   */
   713→  private capabilityCovers(caller: Capability, callee: Capability): boolean {
   714→    if (caller.cap !== callee.cap) return false
   715→    if (!callee.arg) return true // callee가 경로 무관하면 OK
   716→    if (!caller.arg) return false
   717→
   718→    // Path: /tmp → /tmp/file.txt OK, /tmp → /etc NG
   719→    if (caller.cap === "read_file" || caller.cap === "write_file") {
   720→      return this.pathIsUnder(callee.arg, caller.arg)
   721→    }
   722→
   723→    // Network: api.openai.com → api.openai.com OK, *.openai.com → sub.openai.com OK
   724→    if (caller.cap === "network") {
   725→      return this.hostMatches(callee.arg, caller.arg)
   726→    }
   727→
   728→    return caller.arg === callee.arg
   729→  }
   730→
   731→  private pathIsUnder(target: string, allowedPrefix: string): boolean {
   732→    // ".." 즉시 거부
   733→    if (target.includes("..")) return false
   734→    const normalized = target.replace(/\/+/g, "/").replace(/\/$/, "")
   735→    const prefix = allowedPrefix.replace(/\/+/g, "/").replace(/\/$/, "")
   736→    return normalized === prefix || normalized.startsWith(prefix + "/")
   737→  }
   738→
   739→  private hostMatches(target: string, pattern: string): boolean {
   740→    if (pattern === target) return true
   741→    if (pattern.startsWith("*.")) {
   742→      const base = pattern.slice(2)
   743→      return (
   744→        target.endsWith("." + base) &&
   745→        !target.slice(0, -base.length - 1).includes(".")
   746→      )
   747→    }
   748→    return false
   749→  }
   750→}
