     1→// Phase 5.2: TypeInference - 자동 타입 추론 엔진
     2→
     3→import { Stmt } from "./ast"
     4→import {
     5→  Type,
     6→  PrimitiveType,
     7→  Constraint,
     8→  widenType,
     9→  BUILTIN_TYPES,
    10→} from "./type-system"
    11→
    12→/**
    13→ * TypeInference: 타입 미정 변수 자동 추론
    14→ */
    15→export class TypeInference {
    16→  private constraints: Constraint[] = []
    17→  private solutions: Map<string, Type> = new Map()
    18→
    19→  /**
    20→   * 제약 조건 추가
    21→   */
    22→  public addConstraint(
    23→    variable: string,
    24→    expectedType: Type,
    25→    actualType?: Type,
    26→    location?: { line: number; column: number }
    27→  ): void {
    28→    this.constraints.push({
    29→      variable,
    30→      expectedType,
    31→      actualType,
    32→      location,
    33→    })
    34→  }
    35→
    36→  /**
    37→   * 제약 조건 풀기
    38→   */
    39→  public solve(): Map<string, Type> {
    40→    this.solutions.clear()
    41→
    42→    const varConstraints = new Map<string, Constraint[]>()
    43→    for (const constraint of this.constraints) {
    44→      if (!varConstraints.has(constraint.variable)) {
    45→        varConstraints.set(constraint.variable, [])
    46→      }
    47→      varConstraints.get(constraint.variable)!.push(constraint)
    48→    }
    49→
    50→    for (const [variable, constraints] of varConstraints.entries()) {
    51→      if (constraints.length === 0) {
    52→        this.solutions.set(variable, BUILTIN_TYPES.UNKNOWN)
    53→        continue
    54→      }
    55→
    56→      // 하나면 그것
    57→      if (constraints.length === 1) {
    58→        this.solutions.set(variable, constraints[0].expectedType)
    59→        continue
    60→      }
    61→
    62→      // 여러 개면: 차례대로 unify 시도
    63→      // unify 성공 → 더 구체적인 타입
    64→      // unify 실패 → union 생성
    65→      let resultType = constraints[0].expectedType
    66→      const cannotUnify: Type[] = [resultType]
    67→
    68→      for (let i = 1; i < constraints.length; i++) {
    69→        const unified = this.unify(resultType, constraints[i].expectedType)
    70→        if (unified) {
    71→          resultType = unified
    72→        } else {
    73→          // unify 실패 → 따로 기록
    74→          cannotUnify.push(constraints[i].expectedType)
    75→        }
    76→      }
    77→
    78→      // unify 실패한 타입들만 union
    79→      if (cannotUnify.length > 1) {
    80→        resultType = widenType(...cannotUnify)
    81→      } else {
    82→        resultType = cannotUnify[0]
    83→      }
    84→
    85→      this.solutions.set(variable, resultType)
    86→    }
    87→
    88→    return new Map(this.solutions)
    89→  }
    90→
    91→  /**
    92→   * Hindley-Milner 스타일 타입 통일
    93→   */
    94→  public unify(t1: Type, t2: Type): Type | null {
    95→    if (JSON.stringify(t1) === JSON.stringify(t2)) {
    96→      return t1
    97→    }
    98→
    99→    if (t1.kind === "primitive" && t1.type === PrimitiveType.UNKNOWN) {
   100→      return t2
   101→    }
   102→
   103→    if (t2.kind === "primitive" && t2.type === PrimitiveType.UNKNOWN) {
   104→      return t1
   105→    }
   106→
   107→    if (t1.kind === "primitive" && t2.kind === "primitive") {
   108→      return t1.type === t2.type ? t1 : null
   109→    }
   110→
   111→    if (t1.kind === "array" && t2.kind === "array") {
   112→      const elemUnified = this.unify(t1.elementType, t2.elementType)
   113→      if (elemUnified) {
   114→        return { kind: "array", elementType: elemUnified }
   115→      }
   116→      return null
   117→    }
   118→
   119→    if (t1.kind === "fn" && t2.kind === "fn") {
   120→      if (t1.paramTypes.length !== t2.paramTypes.length) {
   121→        return null
   122→      }
   123→
   124→      const unifiedParams: Type[] = []
   125→      for (let i = 0; i < t1.paramTypes.length; i++) {
   126→        const paramUnified = this.unify(t1.paramTypes[i], t2.paramTypes[i])
   127→        if (!paramUnified) {
   128→          return null
   129→        }
   130→        unifiedParams.push(paramUnified)
   131→      }
   132→
   133→      const returnUnified = this.unify(t1.returnType, t2.returnType)
   134→      if (!returnUnified) {
   135→        return null
   136→      }
   137→
   138→      return {
   139→        kind: "fn",
   140→        paramTypes: unifiedParams,
   141→        returnType: returnUnified,
   142→      }
   143→    }
   144→
   145→    if (t1.kind === "object" && t2.kind === "object") {
   146→      const keys1 = Array.from(t1.properties.keys()).sort()
   147→      const keys2 = Array.from(t2.properties.keys()).sort()
   148→
   149→      if (keys1.length !== keys2.length) {
   150→        return null
   151→      }
   152→
   153→      if (!keys1.every((k, i) => k === keys2[i])) {
   154→        return null
   155→      }
   156→
   157→      const unifiedProps = new Map<string, Type>()
   158→      for (const key of keys1) {
   159→        const propUnified = this.unify(
   160→          t1.properties.get(key)!,
   161→          t2.properties.get(key)!
   162→        )
   163→        if (!propUnified) {
   164→          return null
   165→        }
   166→        unifiedProps.set(key, propUnified)
   167→      }
   168→
   169→      return {
   170→        kind: "object",
   171→        properties: unifiedProps,
   172→      }
   173→    }
   174→
   175→    return null
   176→  }
   177→
   178→  /**
   179→   * 함수 반환 타입 추론
   180→   */
   181→  public inferReturnType(
   182→    body: Stmt[],
   183→    env: Map<string, Type>,
   184→    checker: any
   185→  ): Type {
   186→    const returnTypes: Type[] = []
   187→
   188→    const findReturns = (stmts: Stmt[]) => {
   189→      for (const stmt of stmts) {
   190→        if (stmt.kind === "return") {
   191→          const returnStmt = stmt as any
   192→          if (returnStmt.value) {
   193→            const retType = checker.checkExpr(returnStmt.value)
   194→            returnTypes.push(retType)
   195→          }
   196→        } else if (stmt.kind === "if") {
   197→          const ifStmt = stmt as any
   198→          findReturns(ifStmt.then || [])
   199→          if (ifStmt.else) {
   200→            findReturns(ifStmt.else)
   201→          }
   202→        } else if (stmt.kind === "block") {
   203→          const blockStmt = stmt as any
   204→          findReturns(blockStmt.body || [])
   205→        } else if (stmt.kind === "while" || stmt.kind === "for") {
   206→          const loopStmt = stmt as any
   207→          findReturns(loopStmt.body || [])
   208→        }
   209→      }
   210→    }
   211→
   212→    findReturns(body)
   213→
   214→    if (returnTypes.length === 0) {
   215→      return BUILTIN_TYPES.NULL
   216→    }
   217→
   218→    if (returnTypes.length === 1) {
   219→      return returnTypes[0]
   220→    }
   221→
   222→    return widenType(...returnTypes)
   223→  }
   224→
   225→  /**
   226→   * for 루프 변수 타입 추론
   227→   */
   228→  public inferLoopVarType(iterType: Type): Type {
   229→    if (iterType.kind === "array") {
   230→      return iterType.elementType
   231→    }
   232→    return BUILTIN_TYPES.UNKNOWN
   233→  }
   234→
   235→  /**
   236→   * 제약 개수 조회
   237→   */
   238→  public getConstraintCount(): number {
   239→    return this.constraints.length
   240→  }
   241→
   242→  /**
   243→   * 제약 목록 조회
   244→   */
   245→  public getConstraints(): Constraint[] {
   246→    return [...this.constraints]
   247→  }
   248→
   249→  /**
   250→   * 해결된 타입 조회
   251→   */
   252→  public getSolution(variable: string): Type | undefined {
   253→    return this.solutions.get(variable)
   254→  }
   255→}
   256→

