   373→  }
   374→
   375→  function parseImport(): Stmt {
   376→    advance(); // import
   377→    if (at(T.LBrace)) {
   378→      // import { name1, name2 } from "path"
   379→      advance(); // {
   380→      const names: string[] = [];
   381→      while (!at(T.RBrace) && !at(T.EOF)) {
   382→        names.push(expect(T.Ident, "Expected import name").value);
   383→        match(T.Comma);
   384→      }
   385→      expect(T.RBrace);
   386→      expect(T.From, "Expected 'from'");
   387→      const p = expect(T.String, "Expected module path").value;
   388→      match(T.Semicolon);
   389→      return { kind: "import", names, path: p, alias: null };
   390→    } else {
   391→      // import "path" or import "path" as Alias
   392→      const p = expect(T.String, "Expected module path").value;
   393→      let alias: string | null = null;
   394→      if (match(T.As)) alias = expect(T.Ident, "Expected alias name").value;
   395→      match(T.Semicolon);
   396→      return { kind: "import", names: null, path: p, alias };
   397→    }
   398→  }
   399→
   400→  function parseExport(): Stmt {
   401→    advance(); // export
   402→    if (at(T.Fn)) return { kind: "export", stmt: parseFnStmt() };
   403→    if (at(T.Let) || at(T.Const)) return { kind: "export", stmt: parseLetStmt() };
   404→    throw new Error(`Expected fn or let after export at line ${peek().line}`);
   405→  }
   406→
   407→  function parseMatch(): Stmt {
   408→    advance(); // match
   409→    const subject = parseExpr();
   410→    expect(T.LBrace);
   411→    const arms: MatchArm[] = [];
   412→    while (!at(T.RBrace) && !at(T.EOF)) {
   413→      let pattern: Expr | null = null;
   414→      if (at(T.Ident) && peek().value === "_") {
   415→        advance(); // _
   416→      } else {
   417→        pattern = parseExpr();
   418→      }
   419→
   420→      // Parse optional guard clause: if condition
   421→      let guard: Expr | null = null;
   422→      if (match(T.If)) {
   423→        guard = parseExpr();
   424→      }
   425→
   426→      expect(T.FatArrow, "Expected '=>' in match arm");
   427→      let body: Stmt[];
   428→      if (at(T.LBrace)) {
   429→        expect(T.LBrace);
   430→        body = parseBody();
   431→        expect(T.RBrace);
   432→      } else {
   433→        body = [parseStmt()];
   434→      }
   435→      arms.push({ pattern, guard, body });
   436→      match(T.Comma);
   437→    }
   438→    expect(T.RBrace);
   439→    return { kind: "match", subject, arms };
   440→  }
   441→
   442→  function parseExprStmt(): Stmt {
   443→    const expr = parseExpr();
   444→    match(T.Semicolon);
   445→    return { kind: "expr", expr };
   446→  }
   447→
   448→  // --- Expressions (Pratt) ---
   449→  function parseExpr(): Expr { return parseAssign(); }
   450→
   451→  function parseAssign(): Expr {
   452→    let left = parseOr();
   453→    if (at(T.Assign) || at(T.PlusAssign) || at(T.MinusAssign) || at(T.StarAssign) || at(T.SlashAssign)) {
   454→      const op = advance();
   455→      const right = parseAssign();
   456→      if (op.type === T.Assign) return { kind: "assign", target: left, value: right };
   457→      const binOp = op.value[0]; // +, -, *, /
   458→      return { kind: "assign", target: left, value: { kind: "binary", op: binOp, left, right } };
   459→    }
   460→    return left;
   461→  }
   462→
   463→  function parseOr(): Expr {
   464→    let left = parseAnd();
   465→    while (match(T.Or)) left = { kind: "binary", op: "||", left, right: parseAnd() };
   466→    return left;
   467→  }
   468→
   469→  function parseAnd(): Expr {
   470→    let left = parseEquality();
   471→    while (match(T.And)) left = { kind: "binary", op: "&&", left, right: parseEquality() };
   472→    return left;
   473→  }
   474→
   475→  function parseEquality(): Expr {
   476→    let left = parseComparison();
   477→    while (at(T.Eq) || at(T.Neq)) {
   478→      const op = advance().value;
   479→      left = { kind: "binary", op, left, right: parseComparison() };
   480→    }
   481→    return left;
   482→  }
   483→
   484→  function parseComparison(): Expr {
   485→    let left = parseAddition();
   486→    while (at(T.Lt) || at(T.Gt) || at(T.Lte) || at(T.Gte)) {
   487→      const op = advance().value;
   488→      left = { kind: "binary", op, left, right: parseAddition() };
   489→    }
   490→    return left;
   491→  }
   492→
   493→  function parseAddition(): Expr {
   494→    let left = parseMultiplication();
   495→    while (at(T.Plus) || at(T.Minus)) {
   496→      const op = advance().value;
   497→      left = { kind: "binary", op, left, right: parseMultiplication() };
   498→    }
   499→    return left;
   500→  }
   501→
   502→  function parseMultiplication(): Expr {
   503→    let left = parseUnary();
   504→    while (at(T.Star) || at(T.Slash) || at(T.Percent)) {
   505→      const op = advance().value;
   506→      left = { kind: "binary", op, left, right: parseUnary() };
   507→    }
   508→    return left;
   509→  }
   510→
   511→  function parseUnary(): Expr {
   512→    // Handle unary operators: -, !, &, *
   513→    if (at(T.Minus) || at(T.Not) || at(T.Ampersand) || at(T.Star)) {
   514→      const op = advance().value;
   515→      return { kind: "unary", op, expr: parseUnary() };
   516→    }
   517→    return parsePostfix();
   518→  }
   519→
   520→  function parsePostfix(): Expr {
   521→    let expr = parsePrimary();
   522→    while (true) {
   523→      if (match(T.LParen)) {
   524→        const args: Expr[] = [];
   525→        while (!at(T.RParen) && !at(T.EOF)) {
