   536→        const prop = expect(T.Ident, "Expected property name").value;
   537→        expr = { kind: "member", object: expr, property: prop };
   538→      } else break;
   539→    }
   540→    return expr;
   541→  }
   542→
   543→  function parsePrimary(): Expr {
   544→    const t = peek();
   545→    switch (t.type) {
   546→      case T.Number: advance(); return { kind: "number", value: Number(t.value) };
   547→      case T.String: advance(); return { kind: "string", value: t.value };
   548→      case T.Bool: advance(); return { kind: "bool", value: t.value === "true" };
   549→      case T.Null: advance(); return { kind: "null" };
   550→      case T.Ident: {
   551→        advance();
   552→        // Single-param arrow: x => expr
   553→        if (at(T.FatArrow)) {
   554→          advance();
   555→          // Phase 5.5.3: Param 객체로 변환
   556→          const arrowParam: Param = { name: t.value };
   557→          if (at(T.LBrace)) {
   558→            expect(T.LBrace);
   559→            const body = parseBody();
   560→            expect(T.RBrace);
   561→            return { kind: "fn", name: null, params: [arrowParam], body };
   562→          }
   563→          const expr = parseAssign();
   564→          return { kind: "fn", name: null, params: [arrowParam], body: [{ kind: "return", value: expr }] };
   565→        }
   566→        return { kind: "ident", name: t.value };
   567→      }
   568→      case T.LParen: {
   569→        // Try arrow function: (params) => body
   570→        const savedPos = pos;
   571→        advance(); // (
   572→
   573→        // Check for empty parens arrow: () => ...
   574→        if (at(T.RParen)) {
   575→          const rp = pos;
   576→          advance(); // )
   577→          if (at(T.FatArrow)) {
   578→            advance(); // =>
   579→            return parseArrowBody([]);
   580→          }
   581→          // Not arrow, backtrack
   582→          pos = savedPos;
   583→          advance();
   584→          const expr = parseExpr();
   585→          expect(T.RParen);
   586→          return expr;
   587→        }
   588→
   589→        // Try parsing as ident list for arrow function
   590→        let isArrow = true;
   591→        const params: Param[] = [];  // Phase 5.5.3: Param[]로 변경
   592→        const tryPos = pos;
   593→        while (!at(T.RParen) && !at(T.EOF)) {
   594→          if (!at(T.Ident)) { isArrow = false; break; }
   595→          params.push({ name: advance().value });  // Param 객체로
   596→          if (!at(T.RParen)) {
   597→            if (!match(T.Comma)) { isArrow = false; break; }
   598→          }
   599→        }
   600→        if (isArrow && at(T.RParen)) {
   601→          advance(); // )
   602→          if (at(T.FatArrow)) {
   603→            advance(); // =>
   604→            return parseArrowBody(params);
   605→          }
   606→        }
   607→
   608→        // Not arrow, backtrack and parse as grouped expression
   609→        pos = savedPos;
   610→        advance(); // (
   611→        const expr = parseExpr();
   612→        expect(T.RParen);
   613→        return expr;
   614→      }
   615→      case T.LBracket: return parseArrayLiteral();
   616→      case T.LBrace: return parseObjectLiteral();
   617→      case T.Fn: return parseFnExpr();
   618→      case T.If: return parseIfExpr();
   619→      case T.Match: return parseMatchExpr();
   620→      default: throw new Error(`Unexpected token '${t.value}' at line ${t.line}:${t.col}`);
   621→    }
   622→  }
   623→
   624→  function parseArrowBody(params: Param[]): Expr {  // Phase 5.5.3: Param[]
   625→    if (at(T.LBrace)) {
   626→      expect(T.LBrace);
   627→      const body = parseBody();
   628→      expect(T.RBrace);
   629→      return { kind: "fn", name: null, params, body };
   630→    }
   631→    const expr = parseAssign();
   632→    return { kind: "fn", name: null, params, body: [{ kind: "return", value: expr }] };
   633→  }
   634→
   635→  function parseArrayLiteral(): Expr {
   636→    advance(); // [
   637→    const elements: Expr[] = [];
   638→    while (!at(T.RBracket) && !at(T.EOF)) {
   639→      elements.push(parseExpr());
   640→      match(T.Comma);
   641→    }
   642→    expect(T.RBracket);
   643→    return { kind: "array", elements };
   644→  }
   645→
   646→  function parseObjectLiteral(): Expr {
   647→    advance(); // {
   648→    const entries: { key: string; value: Expr }[] = [];
   649→    while (!at(T.RBrace) && !at(T.EOF)) {
   650→      const key = expect(T.Ident, "Expected key").value;
   651→      expect(T.Colon);
   652→      const value = parseExpr();
   653→      entries.push({ key, value });
   654→      match(T.Comma);
   655→    }
   656→    expect(T.RBrace);
   657→    return { kind: "object", entries };
   658→  }
   659→
   660→  function parseFnExpr(): Expr {
   661→    advance(); // fn
   662→    let name: string | null = null;
   663→    if (at(T.Ident)) name = advance().value;
   664→    expect(T.LParen);
   665→    const params = parseParams();
   666→    expect(T.RParen);
   667→    expect(T.LBrace);
   668→    const body = parseBody();
   669→    expect(T.RBrace);
   670→    return { kind: "fn", name, params, body };
   671→  }
   672→
   673→  function parseParams(): Param[] {
   674→    const params: Param[] = [];
   675→    while (!at(T.RParen) && !at(T.EOF)) {
   676→      const paramName = expect(T.Ident, "Expected parameter name").value;
   677→      let typeAnnotation: string | undefined;
   678→      // Phase 5.5.3: 타입 어노테이션 수집 (버리지 않고 저장)
   679→      if (match(T.Colon)) {
   680→        const typeParts: string[] = [];
   681→        let depth = 0;
   682→        while (!at(T.Comma) && !at(T.RParen) && !at(T.EOF)) {
   683→          const tok = advance();
   684→          if (tok.type === T.LBracket) depth++;
   685→          if (tok.type === T.RBracket) depth--;
   686→          if (depth < 0) break;
   687→          typeParts.push(tok.value);
   688→        }
   689→        typeAnnotation = typeParts.join("").toLowerCase();
   690→      }
   691→      params.push({ name: paramName, typeAnnotation });
   692→      match(T.Comma);
   693→    }
   694→    return params;
   695→  }
   696→
   697→  // Phase 6: Parse capability annotations [allow(...), limit(...)]
   698→  function parseAnnotations(): any[] {
   699→    if (!at(T.LBracket)) return []
   700→    advance() // [
   701→    const annotations: any[] = []
   702→
   703→    while (!at(T.RBracket) && !at(T.EOF)) {
   704→      const name = expect(T.Ident).value // "allow" or "limit"
   705→
   706→      if (name === "allow") {
   707→        expect(T.LParen)
   708→        const capName = expect(T.Ident).value // read_file, network, etc
   709→        let arg: string | undefined
   710→        if (match(T.LParen)) {
   711→          // allow(read_file("/tmp")) — consume string arg
   712→          arg = expect(T.String).value
   713→          expect(T.RParen)
   714→        }
   715→        expect(T.RParen)
   716→        annotations.push({ kind: "allow", cap: capName, arg })
   717→      } else if (name === "limit") {
   718→        expect(T.LParen)
   719→        while (!at(T.RParen) && !at(T.EOF)) {
   720→          const res = expect(T.Ident).value // cpu, memory, io
   721→          expect(T.Assign)
   722→          const val = Number(expect(T.Number).value)
   723→          annotations.push({ kind: "limit", resource: res, value: val })
   724→          match(T.Comma)
   725→        }
   726→        expect(T.RParen)
   727→      }
   728→
   729→      match(T.Comma)
   730→    }
   731→
   732→    expect(T.RBracket) // ]
   733→    return annotations
   734→  }
   735→
   736→  function parseBody(): Stmt[] {
   737→    const stmts: Stmt[] = [];
   738→    while (!at(T.RBrace) && !at(T.EOF)) stmts.push(parseStmt());
   739→    return stmts;
   740→  }
   741→
   742→  return parseProgram();
   743→}
